      optimization: {
        strategy: 'balanced',
        maxCostPerTask: 0.5,
      },
    };
  }

  /**
   * Get default providers list
   */
  private getDefaultProviders(): ProviderConfig[] {
    return Object.values(this.getDefaultConfig().providers);
  }
}

